var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하, 하하…… 카린 양?","JPN":"ハ、ハハ……カリンさん？","ENG":"Ha, ha ha... Karin?","TWN":"哈，哈哈……卡琳？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무리 작전이라고 해도, 이건 좀 아닌 거 같지 않아요?","JPN":"いくら作戦だといっても、これは違うんじゃないですかね。","ENG":"Even for an operation, isn't this a bit too risky?","TWN":"雖說是作戰，但好像哪裡不太對？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"괜히 이런 곳에 있다가, 저 고치를 자극해서 좋을 게 없다고 생각하는데요?","JPN":"こんなところに来てあの繭を刺激しても、何もいいことないですよ？","ENG":"If we lounge around here, we might end up provoking that cocoon.","TWN":"我覺得我們待在這裡會刺激到那個繭，這對我們來說沒有任何好處。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저도 시영 씨 의견에 동의해요.","JPN":"私もシノンさんの意見に同意します。","ENG":"I agree with you, Shiyoung.","TWN":"我很贊成你的想法。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그렇죠? 그럼 어서 여기서 벗어나자구요.","JPN":"ですよね？　それじゃあ、早くここから出ましょう。","ENG":"Right? Okay, then let's get out of here.","TWN":"是吧？那我們趕緊離開這裡吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"거절하겠어요, 시영 씨. 왜냐하면…… 여기에 있다는 정보를 얻었거든요.","JPN":"お断りします、シノンさん。なぜなら……ここに存在するという情報を手に入れましたので。","ENG":"I refuse, Shiyoung. Because... I received intel, that it is here.","TWN":"我拒絕。因為……據我得到情報所描述，東西就在這個地方。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"있다고요? 뭐가요? 설마 유령이?","JPN":"存在する？　何がですか？　もしかして、幽霊？","ENG":"It? What's it? A ghost?","TWN":"就在這個地方？什麼東西？莫非是幽靈？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"유, 유령!?","JPN":"ゆ、幽霊！？","ENG":"A-a ghost?!","TWN":"幽，幽靈？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어, 어디…… 어디에요!?","JPN":"ど、どこ……どこですか！？","ENG":"W-where... Where is it?!","TWN":"在，在……在哪裡啊？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아, 아니야! 이 세상에 유령 같은 건 없다고요! 장난치지 마세요, 시영 씨!","JPN":"い、いいえ！　この世に幽霊なんていません！　からかわないでください、シノンさん！","ENG":"N-no! There's no such thing as ghosts! Stop joking around, Shiyoung!","TWN":"不，不！這個世界上才沒有幽靈！你別開玩笑了，時雨！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아무튼 제가 말하려던 건, 이곳 어딘가 소원을 이루어 주는 <color=#ffd34c>아티팩트</color>가 있다는 제보를 받았기 때문이에요.","JPN":"とにかく、私が言おうとしていたのは、ここのどこかに願いを叶えてくれる<color=#ffd34c>アーティファクト</color>があるという情報を得たからです。","ENG":"Well, what I was trying to say was that there's an <color=#ffd34c>Artifact</color> that grants wishes somewhere around here.","TWN":"總之，我想說的是，我得到消息說在這地方的某處，有可以實現願望的<color=#ffd34c>人造神器</color>。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"소원을 이루어 준다고요?","JPN":"願いを叶えてくれる？","ENG":"Grants wishes?","TWN":"可以實現願望？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이, 말도 안 돼. 그런 게 있으면 우리 세계가 이렇게 막장이 되었을 리 없잖아요.","JPN":"またまた。あり得ません。そんなものがあったら、私たちの世界はこんなに追い詰められてませんよ。","ENG":"No way. If that really existed, our world would never be this disastrous.","TWN":"哈哈！騙人的吧？要是真有那種東西，那我們的世界也不至於變得這麼糟糕。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네. 하지만 충분히 검증해볼 필요는 있어요.","JPN":"はい。ですが、検証してみる必要はあると思います。","ENG":"Right, but it's still worth investigating.","TWN":"嗯，不過，我們需要充分驗證一下。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리가 찾는 아티팩트에는 <color=#ffd34c>원숭이 손</color>이라는 이름이 붙어 있다고 하니까요.","JPN":"私たちが探しているアーティファクトには、<color=#ffd34c>サルの手</color>という名前がついているらしいですから。","ENG":"It is said that the Artifact we're looking for is called the <color=#ffd34c>Monkey's Paw</color>.","TWN":"我們要找的人造神器叫作<color=#ffd34c>猴爪</color>。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? <color=#ffd34c>원숭이 손</color>?","JPN":"はい？　<color=#ffd34c>サルの手</color>？","ENG":"Huh? <color=#ffd34c>Monkey's Paw</color>?","TWN":"什麼？<color=#ffd34c>猴爪</color>？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하. 왠지 소원을 들어주긴 하는데, 요상한 방식으로 이루어 줄 것 같은 이름인데요?","JPN":"ハハ。なんだか願いを叶えてはくれるけど、変な形で叶えてくれそうな名前ですね。","ENG":"Ha ha. That sounds like a name that would grant wishes, but in a twisted way.","TWN":"哈哈，感覺雖然能實現願望，但聽起來似乎會用奇怪的方法實現？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};